contract EthTxOrderDependenceMinimal {
    address public owner;
    bool public claimed;
    uint public reward;

    function EthTxOrderDependenceMinimal() public {
        owner = msg.sender;
    }

    function setReward() public payable {
        require(!claimed);

        require(msg.sender == owner);

        owner.transfer(reward);
        reward = msg.value;
    }

    function claimReward(uint256 submission) {
        require(!claimed);
        require(submission < 10);

        msg.sender.transfer(reward);
        claimed = true;
    }
}
```
Output:
- Access Control: Present
Explanation: The `setReward` function allows only the owner to set the reward, but there are no restrictions on who can call the `claimReward` function. Anyone can call `claimReward` and potentially steal the reward, as long as the `submission` value meets the requirement.

