        uint n = players[0].number + players[1].number;
        if (n % 2 == 0) {
            res = players[0].addr.send(1800 finney);
        } else {
            res = players[1].addr.send(1800 finney);
        }

        delete players;
        tot = 0;
    }

    function getProfit() {
        if (msg.sender != owner) throw;
        bool res = msg.sender.send(this.balance);
    }
}

