    modifier onlywizard() {
        if (msg.sender == wizardAddress) _;
    }

    uint constant startingClaimPrice = 100 finney;

    uint constant claimPriceAdjustNum = 3;
    uint constant claimPriceAdjustDen = 2;

    uint constant wizardCommissionFractionNum = 1;
    uint constant wizardCommissionFractionDen = 100;

    uint public currentClaimPrice;

    Monarch public currentMonarch;

    Monarch[] public pastMonarchs;

    function KingOfTheEtherThrone() {
        wizardAddress = msg.sender;
        currentClaimPrice = startingClaimPrice;
        currentMonarch = Monarch(wizardAddress, "[Vacant]", 0, block.timestamp);
    }

    function numberOfMonarchs() constant returns (uint n) {
        return pastMonarchs.length;
    }

    event ThroneClaimed(
        address usurperEtherAddress,
        string usurperName,
        uint newClaimPrice
    );

    function() {
        claimThrone(string(msg.data));
    }

    function claimThrone(string name) {
        uint valuePaid = msg.value;

        if (valuePaid < currentClaimPrice) {
            msg.sender.send(valuePaid);
            return;
        }

        if (valuePaid > currentClaimPrice) {
            uint excessPaid = valuePaid - currentClaimPrice;

            msg.sender.send(excessPaid);
            valuePaid = valuePaid - excessPaid;
        }

        uint wizardCommission = (valuePaid * wizardCommissionFractionNum) /
            wizardCommissionFractionDen;

        uint compensation = valuePaid - wizardCommission;

        if (currentMonarch.etherAddress != wizardAddress) {
            currentMonarch.etherAddress.send(compensation);
        } else {}

        pastMonarchs.push(currentMonarch);
        currentMonarch = Monarch(msg.sender, name, valuePaid, block.timestamp);

        uint rawNewClaimPrice = (currentClaimPrice * claimPriceAdjustNum) /
            claimPriceAdjustDen;
        if (rawNewClaimPrice < 10 finney) {
            currentClaimPrice = rawNewClaimPrice;
        } else if (rawNewClaimPrice < 100 finney) {
            currentClaimPrice = 100 szabo * (rawNewClaimPrice / 100 szabo);
        } else if (rawNewClaimPrice < 1 ether) {
            currentClaimPrice = 1 finney * (rawNewClaimPrice / 1 finney);
        } else if (rawNewClaimPrice < 10 ether) {
            currentClaimPrice = 10 finney * (rawNewClaimPrice / 10 finney);
        } else if (rawNewClaimPrice < 100 ether) {
            currentClaimPrice = 100 finney * (rawNewClaimPrice / 100 finney);
        } else if (rawNewClaimPrice < 1000 ether) {
            currentClaimPrice = 1 ether * (rawNewClaimPrice / 1 ether);
        } else if (rawNewClaimPrice < 10000 ether) {
            currentClaimPrice = 10 ether * (rawNewClaimPrice / 10 ether);
        } else {
            currentClaimPrice = rawNewClaimPrice;
        }

        ThroneClaimed(
            currentMonarch.etherAddress,
            currentMonarch.name,
            currentClaimPrice
        );
    }

    function sweepCommission(uint amount) onlywizard {
        wizardAddress.send(amount);
    }

    function transferOwnership(address newOwner) onlywizard {
        wizardAddress = newOwner;
    }
}
```
Output:
- Access Control: Present
Explanation: The contract allows the `wizardAddress` to be set as the initial owner and to perform special functions like `sweepCommission` and `transferOwnership`. There are no further checks to prevent unauthorized users from invoking these functions.

- Arithmetic: Absent
Explanation: The contract does not perform any arithmetic operations that could lead to overflow or underflow issues.

- Bad Randomness: Absent
Explanation: The contract does not rely on any random number generation, so there is no bad randomness issue.

- Denial Of Service: Absent
Explanation: The contract does not seem to have a mechanism that could cause denial of service by consuming excessive resources.

- Front Running: Uncertain
Explanation: The contract does not expose a transaction-order-dependent action or secret that could be exploited by observing pending transactions. However, without more context about the `claimThrone` function's behavior, we cannot conclusively rule out front running.

- Reentrancy: Absent
Explanation: The `claimThrone` function does not make any external calls or recursive calls that could be exploited for a reentrancy attack. All state changes occur before any external calls are made.

- Short Addresses: Absent
Explanation: The contract does not process external address inputs in a way that suggests a short address issue. It always uses the full 20-byte address for `etherAddress`.

- Time Manipulation: Absent
Explanation: The contract does not directly depend on the block timestamp in a way that could be manipulated by miners. However, the `claimThrone` function could be vulnerable if the block timestamp is influenced, although this is not explicitly checked or relied upon.

- Unchecked Low Level Calls: Absent
Explanation: The contract does not use low-level calls such as `call`, `delegatecall`, or `send` in a way that could lead to unchecked low-level call vulnerabilities.

